SELECT * FROM episode_source
WHERE content_id = #{contentId}
  AND season = #{season}
  AND episode = #{episode}
  AND 
    translator_id IS NULL
    translator_id = #{translatorId}

  AND provider = #{provider}
LIMIT 1
